"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[30118],{50376:e=>{e.exports=JSON.parse('{"tag":{"label":"endocrine","permalink":"/docs/tags/endocrine","allTagsPath":"/docs/tags","count":2,"items":[{"id":"Rats/illnesses-and-conditions/diabetes-in-rats","title":"Diabetes in Rats","description":"Diabetes Mellitus is a condition in which the body either fails to produce enough insulin or cannot use it effectively, resulting in persistently high blood sugar (hyperglycemia). While not common in pet rats, it does occur \u2014 particularly in older or overweight individuals \u2014 and requires prompt veterinary attention and a committed management plan. Understanding the signs, how diagnosis works, and what treatment looks like can make a significant difference for an affected rat 1.","permalink":"/docs/Rats/illnesses-and-conditions/diabetes-in-rats"},{"id":"Ferrets/illnesses-and-conditions/diabetes-in-ferrets","title":"Understanding Diabetes in Ferrets","description":"When discussing pancreatic diseases in ferrets, it is crucial to distinguish between two very different conditions: Insulinoma and Diabetes Mellitus.","permalink":"/docs/Ferrets/illnesses-and-conditions/diabetes-in-ferrets"}],"unlisted":false}}')}}]);